python3 -c "import re, sys, pathlib; failed=[]; 
for f in sys.argv[1:]:
  t=pathlib.Path(f).read_text();
  m=re.match(r'^---\n(.*?)\n---', t, re.DOTALL);
  if not m: failed.append(f'{f}: no frontmatter'); continue
  fm=m.group(1)
  if not re.search(r'^title:\s*"[^"]+"\s*$', fm, re.M): failed.append(f'{f}: title missing or unquoted')
  if not re.search(r'^description:\s*"[^"]+"\s*$', fm, re.M): failed.append(f'{f}: description missing or unquoted')
  d=re.search(r'^description:\s*"([^"]+)"', fm, re.M)
  if d and (d.group(1)!=d.group(1).strip() or len(d.group(1))>160): failed.append(f'{f}: description has trailing space or >160 chars')
print('\n'.join(failed) if failed else 'OK'); sys.exit(1 if failed else 0)" social-plus-sdk/getting-started/overview.mdx social-plus-sdk/getting-started/authentication.mdx social-plus-sdk/getting-started/visitor-mode.mdx social-plus-sdk/getting-started/platform-setup/mobile/ios-quick-start.mdx social-plus-sdk/getting-started/platform-setup/mobile/android-quick-start.mdx social-plus-sdk/getting-started/platform-setup/mobile/flutter-quick-start.mdx social-plus-sdk/getting-started/platform-setup/web/web-quick-start.mdx
